{
    "level": "A2–B1",
    "intro": "In this topic you will learn <strong>partitives</strong> - constructions that help <strong>measure uncountable nouns</strong>: <strong>a piece of, a cup of, a glass of, a slice of</strong> etc.",
    "rules": [
        {
            "label": "A piece of",
            "color": "emerald",
            "text": "<strong>A piece / part</strong> of something:",
            "example": "a piece of cake, a piece of advice"
        },
        {
            "label": "A cup of",
            "color": "blue",
            "text": "<strong>A cup / glass</strong> of a drink:",
            "example": "a cup of coffee, a cup of tea"
        },
        {
            "label": "A bottle of",
            "color": "amber",
            "text": "<strong>Bottle</strong> of liquid:",
            "example": "a bottle of water, a bottle of milk"
        }
    ]
}

{
    "title": "1. What are partitives?",
    "intro": "Partitives are ways of measuring uncountable nouns:",
    "items": [
        {
            "label": "Containers",
            "title": "Dishes / Containers",
            "subtitle": "a cup of, a glass of, a bottle of — measurement liquids"
        },
        {
            "label": "Portions",
            "title": "Portions / Parts",
            "subtitle": "a piece of, a slice of, a loaf of — food measurements"
        },
        {
            "label": "Units",
            "title": "Measurement units",
            "subtitle": "a kilo of, a liter of, a pound of — weight and volume"
        }
    ]
}

{
    "title": "2. A piece of - a piece of food",
    "sections": [
        {
            "label": "З їжею",
            "color": "emerald",
            "description": "<strong>A piece of</strong> — для шматків їжі.",
            "examples": [
                {
                    "en": "a piece of cake",
                    "ua": "шматок торта"
                },
                {
                    "en": "a piece of bread",
                    "ua": "a piece of bread"
                },
                {
                    "en": "a piece of cheese",
                    "ua": "a piece of cheese"
                },
                {
                    "en": "a piece of meat",
                    "ua": "a piece of meat"
                }
            ]
        },
        {
            "label": "With abstractions",
            "color": "sky",
            "description": "<strong>A piece of</strong> — for abstract concepts.",
            "examples": [
                {
                    "en": "a piece of advice",
                    "ua": "advice (one)"
                },
                {
                    "en": "a piece of information",
                    "ua": "information (one)"
                },
                {
                    "en": "a piece of news",
                    "ua": "news (one)"
                },
                {
                    "en": "a piece of evidence",
                    "ua": "proof (one)"
                }
            ]
        },
        {
            "label": "With items",
            "color": "amber",
            "description": "<strong>A piece of</strong> — for items.",
            "examples": [
                {
                    "en": "a piece of paper",
                    "ua": "a piece of paper"
                },
                {
                    "en": "a piece of furniture",
                    "ua": "item of furniture"
                },
                {
                    "en": "a piece of luggage",
                    "ua": "item of luggage"
                },
                {
                    "en": "a piece of equipment",
                    "ua": "item of equipment"
                }
            ]
        }
    ]
}

{
    "title": "3. Drinks - cup, glass, bottle",
    "sections": [
        {
            "label": "A cup of - cup",
            "color": "blue",
            "description": "<strong>A cup of</strong> - for hot drinks in a cup.",
            "examples": [
                {
                    "en": "a cup of coffee",
                    "ua": "a cup of coffee"
                },
                {
                    "en": "a cup of tea",
                    "ua": "cup of tea"
                },
                {
                    "en": "a cup of hot chocolate",
                    "ua": "cup of hot chocolate"
                },
                {
                    "en": "two cups of coffee",
                    "ua": "two cups of coffee"
                }
            ]
        },
        {
            "label": "A glass of — glass",
            "color": "sky",
            "description": "<strong>A glass of</strong> — for liquids in a glass.",
            "examples": [
                {
                    "en": "a glass of water",
                    "ua": "a glass of water"
                },
                {
                    "en": "a glass of juice",
                    "ua": "a glass of juice"
                },
                {
                    "en": "a glass of milk",
                    "ua": "a glass of milk"
                },
                {
                    "en": "a glass of wine",
                    "ua": "a glass of wine"
                }
            ]
        },
        {
            "label": "A bottle of — a bottle",
            "color": "purple",
            "description": "<strong>A bottle of</strong> — for liquids in a bottle.",
            "examples": [
                {
                    "en": "a bottle of Water beer",
                    "ua": "пляшка води"
                },
                {
                    "en": "a bottle of milk",
                    "ua": "пляшка молока"
                },
                {
                    "en": "a bottle of wine",
                    "ua": "пляшка вина"
                },
                {
                    "en": "a bottle of beer",
                    "ua": "пляшка пива"
                }
            ]
        }
    ]
}

{
    "title": "4. Portions of food - slice, loaf, bar",
    "sections": [
        {
            "label": "A slice of - a slice",
            "color": "emerald",
            "description": "<strong>A slice of</strong> - for slices.",
            "examples": [
                {
                    "en": "a slice of bread",
                    "ua": "a slice of bread"
                },
                {
                    "en": "a slice of a slice of cheese of</strong> — for loaves.",
                    "ua": "шматок піци"
                },
                {
                    "en": "a slice of cheese",
                    "ua": "скибка сиру"
                },
                {
                    "en": "a slice of cake",
                    "ua": "шматок торта"
                }
            ]
        },
        {
            "label": "A loaf of — буханка",
            "color": "amber",
            "description": "<strong>A loaf of</strong> — для буханок.",
            "examples": [
                {
                    "en": "a loaf of bread",
                    "ua": "buhanka bread"
                },
                {
                    "en": "two loaves of bread",
                    "ua": "two loaves of bread"
                }
            ]
        },
        {
            "label": "A bar of — tile/bar",
            "color": "rose",
            "description": "<strong>A bar of - for tiles / bars. Containers: box, can, jar",
            "examples": [
                {
                    "en": "a bar of chocolate",
                    "ua": "плитка шоколаду"
                },
                {
                    "en": "a bar of soap",
                    "ua": "шматок мила"
                }
            ]
        }
    ]
}

{
    "title": "5. Контейнери — box, can, jar",
    "sections": [
        {
            "label": "A box of — коробка",
            "color": "purple",
            "description": "<strong>A box of</strong> — для речей у коробці.",
            "examples": [
                {
                    "en": "a box of chocolates",
                    "ua": "коробка цукерок"
                },
                {
                    "en": "a box of cereal",
                    "ua": "a box of dry breakfast food"
                },
                {
                    "en": "a box of tissues",
                    "ua": "a box of napkins"
                }
            ]
        },
        {
            "label": "A can of — can (canned)",
            "color": "sky",
            "description": "<strong>A can of</strong> — for canned food.",
            "examples": [
                {
                    "en": "a can of soup",
                    "ua": "a can of soup"
                },
                {
                    "en": "a can of beans",
                    "ua": "a can of beans"
                },
                {
                    "en": "a can of soda",
                    "ua": "a can of soda"
                }
            ]
        },
        {
            "label": "A jar of — jar (glass)",
            "color": "emerald",
            "description": "<strong>A jar of</strong> - for things in a glass jar.",
            "examples": [
                {
                    "en": "a jar of jam",
                    "ua": "a jar of jam"
                },
                {
                    "en": "a jar of honey",
                    "ua": "a jar of honey"
                },
                {
                    "en": "a jar of pickles",
                    "ua": "a jar of pickles cucumbers"
                }
            ]
        }
    ]
}

{
    "title": "6. Bags and bags — bag, packet, carton",
    "sections": [
        {
            "label": "A bag of — a bag ",
            "color": "amber",
            "description": "<strong>A bag of</strong> — for things in a bag or bag.",
            "examples": [
                {
                    "en": "a bag of sugar",
                    "ua": "a bag of sugar"
                },
                {
                    "en": "a bag of a bag of rice of</strong> — for things in a packet.",
                    "ua": "пакет борошна"
                },
                {
                    "en": "a bag of rice",
                    "ua": "мішок рису"
                },
                {
                    "en": "a bag of potatoes",
                    "ua": "мішок картоплі"
                }
            ]
        },
        {
            "label": "A packet of — пачка",
            "color": "rose",
            "description": "<strong>A packet of</strong> — для речей у пачці.",
            "examples": [
                {
                    "en": "a packet of crisps",
                    "ua": "a packet of chips"
                },
                {
                    "en": "a packet of biscuits",
                    "ua": "a packet of biscuits"
                },
                {
                    "en": "a packet of cigarettes",
                    "ua": "a packet of cigarettes"
                }
            ]
        },
        {
            "label": "A carton of - a cardboard box",
            "color": "sky",
            "description": "<strong>A carton of</strong> - for liquids in cardboard packaging.",
            "examples": [
                {
                    "en": "a carton of milk",
                    "ua": "a carton of milk"
                },
                {
                    "en": "a carton of juice",
                    "ua": "a carton of juice"
                },
                {
                    "en": "a carton of eggs",
                    "ua": "a tray of eggs"
                }
            ]
        }
    ]
}

{
    "title": "7. Units of measurement — kilo, liter, pound apples",
    "sections": [
        {
            "label": "A kilo of — кілограм",
            "color": "purple",
            "description": "<strong>A kilo of</strong> — для ваги в кілограмах.",
            "examples": [
                {
                    "en": "a kilo of sugar",
                    "ua": "кілограм цукру"
                },
                {
                    "en": "a kilo of apples",
                    "ua": "кілограм яблук"
                },
                {
                    "en": "two kilos of potatoes",
                    "ua": "two kilos of potatoes"
                }
            ]
        },
        {
            "label": "A liter of — liter",
            "color": "blue",
            "description": "<strong>A liter of</strong> — for volume in liters.",
            "examples": [
                {
                    "en": "a liter of water",
                    "ua": "liter water"
                },
                {
                    "en": "a liter of milk",
                    "ua": "liter milk"
                },
                {
                    "en": "two liters of juice",
                    "ua": "two liters of juice"
                }
            ]
        },
        {
            "label": "A pound of — pound",
            "color": "emerald",
            "description": "<strong>A pound of</strong> — for weight in pounds (British system. Other useful partitives",
            "examples": [
                {
                    "en": "a pound of butter",
                    "ua": "фунт масла"
                },
                {
                    "en": "a pound of coffee",
                    "ua": "фунт кави"
                }
            ],
            "note": "📌 1 pound = приблизно 450 грамів."
        }
    ]
}

{
    "title": "8. Інші корисні партитиви",
    "sections": [
        {
            "label": "A bowl of - a bowl",
            "color": "sky",
            "description": "<strong>A bowl of</strong> - for food in a bowl.",
            "examples": [
                {
                    "en": "a bowl of soup",
                    "ua": "a bowl of soup"
                },
                {
                    "en": "a bowl of cereal",
                    "ua": "a bowl flakes"
                },
                {
                    "en": "a bowl of rice",
                    "ua": "a bowl of rice"
                }
            ]
        },
        {
            "label": "A spoonful of",
            "color": "amber",
            "description": "<strong>A spoonful of</strong> — for one spoon.",
            "examples": [
                {
                    "en": "a spoonful of sugar",
                    "ua": "a spoonful of sugar"
                },
                {
                    "en": "a spoonful of honey",
                    "ua": "a spoonful of honey"
                }
            ]
        },
        {
            "label": "A drop of — drop",
            "color": "rose",
            "description": "<strong>A drop of</strong> — for a drop of liquid. Comparative table of partitives",
            "examples": [
                {
                    "en": "a drop of water",
                    "ua": "крапля води"
                },
                {
                    "en": "a drop of milk",
                    "ua": "крапля молока"
                }
            ]
        }
    ]
}

{
    "title": "9. Порівняльна таблиця партитивів",
    "intro": "Main partitives and their use:",
    "rows": [
        {
            "en": "A piece of",
            "ua": "Schát / part",
            "note": "cake, bread, advice, information, furniture"
        },
        {
            "en": "A cup of",
            "ua": "Cup",
            "note": "coffee, tea, hot chocolate (hot drinks)"
        },
        {
            "en": "A glass of",
            "ua": "Glass",
            "note": "water, juice, milk, wine (cold drinks)"
        },
        {
            "en": "A bottle of",
            "ua": "Bottle",
            "note": "water, milk, wine, beer"
        },
        {
            "en": "A slice of",
            "ua": "Slice / piece",
            "note": "bread, pizza, cheese, cake"
        },
        {
            "en": "A loaf of",
            "ua": "Buhanka",
            "note": "bread (loaves in the plural)"
        },
        {
            "en": "A bar of",
            "ua": "Tile / bar",
            "note": "chocolate, soap"
        }
    ],
    "warning": "📌 Partitives are always used with <strong>of</strong> + uncountable noun!"
}

{
    "title": "10. Typical mistakes",
    "items": [
        {
            "label": "Mistake 1",
            "color": "rose",
            "title": "Forget about of after the partitive.",
            "wrong": "I need a piece advice.",
            "right": "​​​​ <span class="font-mono">I need a piece of advice.</span>"
        },
        {
            "label": "Mistake 2",
            "color": "amber",
            "title": "Wrong partitive plural.",
            "wrong": "two loafs of bread",
            "right": "​​​​ <span class="font-mono">two loaves of bread</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Wrong choice of partitive.",
            "wrong": "a slice of milk (incorrect)",
            "right": "​​​​​​​​​​ / I need some water.</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Артикль a з незлічуваними.",
            "wrong": "I need a water.",
            "right": "✅ <span class="font-mono">I need a glass of water. / I need some water.</span>"
        }
    ]
}

{
    "title": "12. Practice",
    "select_title": "Exercise 1. Choose the correct partitive",
    "select_intro": "Choose the correct construction for each noun.",
    "selects": [
        {
            "label": "I need ___ advice. (a piece of / a cup of)",
            "prompt": "What partitive?"
        },
        {
            "label": "Can I have ___ water? (a slice of / a glass of)",
            "prompt": "What partitive?"
        },
        {
            "label": "She bought ___ bread. (a loaf of / a bottle of)",
            "prompt": "What partitive?"
        },
        {
            "label": "I want ___ chocolate. (a slice of/a bar of) information.",
            "prompt": "Який партитив?"
        }
    ],
    "options": [
        "Перший варіант",
        "Другий варіант"
    ],
    "input_title": "Вправа 2. Заповни пропуски",
    "input_intro": "Напиши правильний партитив (з of).",
    "inputs": [
        {
            "before": "I need ___ information.",
            "after": "→"
        },
        {
            "before": "Can I have ___ coffee?",
            "after": "→"
        },
        {
            "before": "She bought ___ jam.",
            "after": "→"
        }
    ],
    "rephrase_title": "Exercise 3. Error correction",
    "rephrase_intro": "Find and correct the error with partitive.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "I need a advice.",
            "example_target": "I need a piece of advice. / I need some advice."
        },
        {
            "original": "1. Can I have a cup coffee?",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. She bought two loaves of bread.",
            "placeholder": "Correct the error"
        }
    ]
}

{
    "title": "Other pages from the category Nouns, articles and quantity",
    "items": [
        {
            "label": "Partitives — a piece of, a cup of… (current)",
            "current": true
        },
        {
            "label": "Quantifiers — Much, Many, A Lot, Few, Little",
            "current": false
        },
        {
            "label": "Countable vs Uncountable - Countable / uncountable ",
            "current": false
        },
        {
            "label": "Articles A / An / The - Articles",
            "current": false
        }
    ]
}
